92→    public Fetch<K, V> collectFetch(final FetchBuffer fetchBuffer) {
    93→        final Fetch<K, V> fetch = Fetch.empty();
    94→        final Queue<CompletedFetch> pausedCompletedFetches = new ArrayDeque<>();
    95→        int recordsRemaining = fetchConfig.maxPollRecords;
    96→
    97→        try {
    98→            while (recordsRemaining > 0) {
    99→                final CompletedFetch nextInLineFetch = fetchBuffer.nextInLineFetch();
   100→
   101→                if (nextInLineFetch == null || nextInLineFetch.isConsumed()) {
   102→                    final CompletedFetch completedFetch = fetchBuffer.peek();
   103→
   104→                    if (completedFetch == null)
   105→                        break;
   106→
   107→                    if (!completedFetch.isInitialized()) {
   108→                        try {
   109→                            fetchBuffer.setNextInLineFetch(initialize(completedFetch));
   110→                        } catch (Exception e) {
   111→                            // Remove a completedFetch upon a parse with exception if (1) it contains no completedFetch, and
   112→                            // (2) there are no fetched completedFetch with actual content preceding this exception.
   113→                            // The first condition ensures that the completedFetches is not stuck with the same completedFetch
   114→                            // in cases such as the TopicAuthorizationException, and the second condition ensures that no
   115→                            // potential data loss due to an exception in a following record.
   116→                            if (fetch.isEmpty() && FetchResponse.recordsOrFail(completedFetch.partitionData).sizeInBytes() == 0)
   117→                                fetchBuffer.poll();
   118→
   119→                            throw e;
   120→                        }
   121→                    } else {
   122→                        fetchBuffer.setNextInLineFetch(completedFetch);
   123→                    }
   124→
   125→                    fetchBuffer.poll();
   126→                } else if (subscriptions.isPaused(nextInLineFetch.partition)) {
   127→                    // when the partition is paused we add the records back to the completedFetches queue instead of draining
   128→                    // them so that they can be returned on a subsequent poll if the partition is resumed at that time
   129→                    log.debug("Skipping fetching records for assigned partition {} because it is paused", nextInLineFetch.partition);
   130→                    pausedCompletedFetches.add(nextInLineFetch);
   131→                    fetchBuffer.setNextInLineFetch(null);
   132→                } else {
   133→                    final Fetch<K, V> nextFetch = fetchRecords(nextInLineFetch, recordsRemaining);
   134→                    recordsRemaining -= nextFetch.numRecords();
   135→                    fetch.add(nextFetch);
   136→                }
   137→            }
   138→        } catch (KafkaException e) {
   139→            if (fetch.isEmpty())
   140→                throw e;
   141→        } finally {
   142→            // add any polled completed fetches for paused partitions back to the completed fetches queue to be
   143→            // re-evaluated in the next poll
   144→            fetchBuffer.addAll(pausedCompletedFetches);
   145→        }
   146→
